import {ApiService} from "@/api/ApiService";

export class ImageService extends ApiService {
    constructor() { super("image"); }

    public async insertImage(
        contentId: number | null,
        historyId: number,
        image: File,
        isAvatar: boolean = true): Promise<number> {
        const formData = new FormData();

        formData.append("Image", image);
        if (contentId != null) formData.append("ContentId", contentId.toString());
        formData.append("HistoryId", historyId.toString());
        formData.append("IsAvatar", isAvatar.toString());

        const path = `${this.hostPath}${this.servicePath}/content/insert`;
        const response = await fetch(path, {
            method: "POST",
            body: formData,
            credentials: "include"
        });
        const body = await response.json() as InsertContentImageResponse;
        return body.ImageId;
    }

    public async unlinkContentImage(
        contentId: number | null,
        historyId: number | null,
        imageId: number | null,
        imageName: string | null
    ): Promise<void> {
        const path = `${this.hostPath}${this.servicePath}/content/unlink`;
        const headers = new Headers();
        headers.set('Content-Type', 'application/json; charset=utf-8');

        await fetch(path, {
            method: "DELETE",
            headers,
            credentials: 'include',
            body: JSON.stringify({
                ContentId: contentId,
                HistoryId: historyId,
                ImageId: imageId,
                ImageName: imageName
            })
        });
    }
}

type InsertContentImageResponse = {
    ImageId: number
}